import { Link } from 'react-router-dom';
import { useState, useEffect } from 'react';

const categories = ['Technology', 'Health', 'Education', 'Environment', 'Art', 'Social Impact'];

/* ═══════════════════════════════════════
   PEOPLE MOSAIC — Backers & Innovators
═══════════════════════════════════════ */

const INNOVATORS = [
  {
    img: 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=400&h=400&fit=crop&crop=face',
    name: 'Priya Menon',
    role: 'Biotech Founder',
    label: 'Innovator',
    accent: '#00d4aa',
  },
  {
    img: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=400&fit=crop&crop=face',
    name: 'James Osei',
    role: 'Hardware Engineer',
    label: 'Innovator',
    accent: '#00d4aa',
  },
  {
    img: 'https://images.unsplash.com/photo-1580489944761-15a19d654956?w=400&h=400&fit=crop&crop=face',
    name: 'Sofia Reyes',
    role: 'EdTech Creator',
    label: 'Innovator',
    accent: '#00d4aa',
  },
  {
    img: 'https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?w=400&h=400&fit=crop&crop=face',
    name: 'Marcus Webb',
    role: 'CleanTech Engineer',
    label: 'Innovator',
    accent: '#00d4aa',
  },
];

const BACKERS = [
  {
    img: 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=400&h=400&fit=crop&crop=face',
    name: 'Nina Hartley',
    role: 'Angel Investor',
    label: 'Backer',
    accent: '#f59e0b',
  },
  {
    img: 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=400&h=400&fit=crop&crop=face',
    name: 'Arjun Shah',
    role: 'Tech Enthusiast',
    label: 'Backer',
    accent: '#f59e0b',
  },
  {
    img: 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=400&h=400&fit=crop&crop=face',
    name: 'Leila Nasri',
    role: 'Impact Investor',
    label: 'Backer',
    accent: '#f59e0b',
  },
  {
    img: 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=400&h=400&fit=crop&crop=face',
    name: 'Ryan Torres',
    role: 'Serial Backer',
    label: 'Backer',
    accent: '#f59e0b',
  },
];

function PeopleCard({ person, index }) {
  const [hovered, setHovered] = useState(false);
  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        position: 'relative',
        borderRadius: 18,
        overflow: 'hidden',
        cursor: 'pointer',
        transition: 'transform 0.3s, box-shadow 0.3s',
        transform: hovered ? 'translateY(-8px) scale(1.02)' : 'translateY(0) scale(1)',
        boxShadow: hovered ? `0 20px 50px ${person.accent}33` : '0 4px 20px #00000055',
        border: `1px solid ${hovered ? person.accent + '55' : '#1f2937'}`,
        aspectRatio: '3/4',
      }}
    >
      <img
        src={person.img}
        alt={person.name}
        style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block' }}
      />
      {/* Gradient overlay */}
      <div style={{
        position: 'absolute', inset: 0,
        background: `linear-gradient(to top, ${person.accent}ee 0%, ${person.accent}22 45%, transparent 70%)`,
        opacity: hovered ? 1 : 0.75,
        transition: 'opacity 0.3s',
      }} />
      {/* Label badge */}
      <div style={{
        position: 'absolute', top: 12, left: 12,
